 37→/**
 38→ * The card template previewer intent must supply one or more cards to show and the index in the list from where
 39→ * to begin showing them. Special rules are applied if the list size is 1 (i.e., no scrolling
 40→ * buttons will be shown).
 41→ */
 42→@NeedsTest("after switch to new schema as default, add test to confirm audio tags rendered")
 43→open class CardTemplatePreviewer : AbstractFlashcardViewer() {
 44→    private var mEditedModelFileName: String? = null
 45→    private var mEditedNotetype: NotetypeJson? = null
 46→    private var mOrdinal = 0
 47→
 48→    /** The index of the card in cardList to show  */
 49→    private var mCardListIndex = 0
 50→
 51→    /** The list (currently singular) of cards to be previewed
 52→     * A single template was selected, and there was an associated card which exists
 53→     */
 54→    private var mCardList: LongArray? = null
 55→    private var mNoteEditorBundle: Bundle? = null
 56→    private var mShowingAnswer = false
 57→
 58→    /**
 59→     * The number of valid cards for the note
 60→     * Only used if mNoteEditorBundle != null
 61→     *
 62→     * If launched from the Template Editor, only one the selected card template is selectable
 63→     */
 64→    private var cardCount = 0
 65→
 66→    /**
 67→     * The index of the selected card in the previewer. Used for forward/back
 68→     * For cloze note types, this may not be the same as `ord`: `{{c1::A}} {{c3::B}}`
 69→     */
 70→    var cardIndex = 0
 71→        private set
 72→    private var mAllFieldsNull = true
 73→    private var mCardType: String? = null
 74→    protected var previewLayout: PreviewLayout? = null
 75→    override fun onCreate(savedInstanceState: Bundle?) {
 76→        if (showedActivityFailedScreen(savedInstanceState)) {
 77→            return
 78→        }
 79→        super.onCreate(savedInstanceState)
 80→        var parameters = savedInstanceState
 81→        if (parameters == null) {
 82→            parameters = intent.extras
 83→        }
 84→        if (parameters != null) {
 85→            mNoteEditorBundle = parameters.getBundle("noteEditorBundle")
 86→            mEditedModelFileName = parameters.getString(CardTemplateNotetype.INTENT_MODEL_FILENAME)
 87→            mCardList = parameters.getLongArray("cardList")
 88→            mOrdinal = parameters.getInt("ordinal")
 89→            mCardListIndex = parameters.getInt("cardListIndex")
 90→            mShowingAnswer = parameters.getBoolean("showingAnswer", mShowingAnswer)
 91→        }
 92→        if (mEditedModelFileName != null) {
 93→            Timber.d("onCreate() loading edited model from %s", mEditedModelFileName)
 94→            try {
 95→                mEditedNotetype = CardTemplateNotetype.getTempModel(mEditedModelFileName!!)
 96→                mCardType = mEditedNotetype!!.optString("name")
 97→            } catch (e: IOException) {
 98→                Timber.w(e, "Unable to load temp model from file %s", mEditedModelFileName)
 99→                closeCardTemplatePreviewer()
100→            }
101→        }
102→        showBackIcon()
103→        // Ensure navigation drawer can't be opened. Various actions in the drawer cause crashes.
104→        disableDrawerSwipe()
105→        startLoadingCollection()
106→    }
107→
108→    override fun onResume() {
109→        super.onResume()
110→        if (currentCard == null || mOrdinal < 0) {
111→            Timber.e("CardTemplatePreviewer started with empty card list or invalid index")
112→            closeCardTemplatePreviewer()
113→        }
114→    }
115→
116→    private fun closeCardTemplatePreviewer() {
117→        Timber.d("CardTemplatePreviewer:: closeCardTemplatePreviewer()")
118→        setResult(RESULT_OK)
119→        CardTemplateNotetype.clearTempModelFiles()
120→        finishWithAnimation(ActivityTransitionAnimation.Direction.END)
121→    }
122→
123→    @Suppress("DEPRECATION", "Deprecated in API34+dependencies for predictive back feature")
124→    override fun onBackPressed() {
125→        Timber.i("CardTemplatePreviewer:: onBackPressed()")
126→        super.onBackPressed()
127→        closeCardTemplatePreviewer()
128→    }
129→
130→    override fun performReload() {
131→        // This should not happen.
132→        finishWithAnimation(ActivityTransitionAnimation.Direction.END)
133→    }
134→
135→    override fun onNavigationPressed() {
136→        Timber.i("CardTemplatePreviewer:: Navigation button pressed")
137→        closeCardTemplatePreviewer()
138→    }
139→
140→    override fun initLayout() {
141→        super.initLayout()
142→        topBarLayout!!.visibility = View.GONE
143→        findViewById<View>(R.id.answer_options_layout).visibility = View.GONE
144→        findViewById<View>(R.id.bottom_area_layout).visibility = View.VISIBLE
145→        previewLayout = createAndDisplay(this, mToggleAnswerHandler)
146→        previewLayout!!.setOnPreviousCard { onPreviousCard() }
147→        previewLayout!!.setOnNextCard { onNextCard() }
148→        previewLayout!!.hideNavigationButtons()
149→        previewLayout!!.setPrevButtonEnabled(false)
150→    }
151→
152→    override fun displayCardQuestion() {
153→        super.displayCardQuestion()
154→        mShowingAnswer = false
155→        previewLayout!!.setShowingAnswer(false)
156→    }
157→
158→    override fun displayCardAnswer() {
159→        if (mAllFieldsNull && mCardType != null && mCardType == getString(R.string.basic_typing_model_name)) {
160→            answerField!!.setText(getString(R.string.basic_answer_sample_text_user))
161→        }
162→        super.displayCardAnswer()
163→        mShowingAnswer = true
164→        previewLayout!!.setShowingAnswer(true)
165→    }
166→
167→    override fun hideEaseButtons() {
168→        /* do nothing */
169→    }
170→
171→    override fun displayAnswerBottomBar() {
172→        /* do nothing */
173→    }
