223→    public override fun onSaveInstanceState(outState: Bundle) {
224→        outState.putString(CardTemplateNotetype.INTENT_MODEL_FILENAME, mEditedModelFileName)
225→        outState.putLongArray("cardList", mCardList)
226→        outState.putInt("ordinal", mOrdinal)
227→        outState.putInt("cardListIndex", mCardListIndex)
228→        outState.putBundle("noteEditorBundle", mNoteEditorBundle)
229→        outState.putBoolean("showingAnswer", mShowingAnswer)
230→        super.onSaveInstanceState(outState)
231→    }
