377→    /** Override certain aspects of Card behavior so we may display unsaved data  */
378→    inner class PreviewerCard : Card {
379→        private val mNote: Note?
380→
381→        constructor(col: Collection, id: Long) : super(col, id) {
382→            mNote = null
383→        }
384→
385→        /* if we have an unsaved note saved, use it instead of a collection lookup */ override fun note(
386→            reload: Boolean
387→        ): Note {
388→            return mNote ?: super.note(reload)
389→        }
390→
391→        /** if we have an unsaved note saved, use it instead of a collection lookup  */
392→        override fun note(): Note {
393→            return mNote ?: super.note()
394→        }
395→
396→        /** if we have an unsaved note, never return empty  */
397→        val isEmpty: Boolean
398→            get() = mNote != null
399→
400→        /** Override the method that fetches the model so we can render unsaved models  */
401→        override fun model(): NotetypeJson {
402→            return mEditedNotetype ?: super.model()
403→        }
404→
405→        override fun renderOutput(reload: Boolean, browser: Boolean): TemplateRenderOutput {
406→            if (renderOutput == null || reload) {
407→                val index = if (model().isCloze) {
408→                    0
409→                } else {
410→                    ord
411→                }
412→                val context = TemplateManager.TemplateRenderContext.fromCardLayout(
413→                    note(),
414→                    this,
415→                    model(),
416→                    model().getJSONArray("tmpls")[index] as JSONObject,
417→                    fillEmpty = false
418→                )
419→                renderOutput =
420→                    context.render()
421→            }
422→            return renderOutput!!
423→        }
424→    }
425→}
426→
427→private class EphemeralCard(col: Collection, id: Long?) : Card(col, id) {
428→    override fun renderOutput(reload: Boolean, browser: Boolean): TemplateRenderOutput {
429→        return this.renderOutput!!
430→    }
431→    companion object {
432→        fun fromNote(n: Note, col: Collection, cardIndex: Int = 0): EphemeralCard {
433→            val card = EphemeralCard(col, null)
434→            card.did = 1
435→            card.ord = n.cardIndexToOrd(cardIndex)
436→
437→            val nt = n.notetype
438→            val templateIdx = if (nt.type == Consts.MODEL_CLOZE) {
439→                0
440→            } else {
441→                cardIndex
442→            }
443→            val template = nt.tmpls[templateIdx] as JSONObject
444→            template.put("ord", card.ord)
445→
446→            val output = TemplateManager.TemplateRenderContext.fromCardLayout(
447→                n,
448→                card,
449→                notetype = nt,
450→                template = template,
451→                fillEmpty = false
452→            ).render()
453→            card.renderOutput = output
454→            card.setNote(n)
455→            return card
456→        }
457→    }
458→}
