460→/** returns the number of cards from a note which has not had data saved in the database */
461→private fun Note.numberOfCardsEphemeral(): Int {
462→    // We can't use note.numberOfCards() as this uses the database value
463→    return when {
464→        this.notetype.isCloze -> col.clozeNumbersInNote(this).size
465→        else -> notetype.templatesNames.size
466→    }
467→}
468→
469→/**
470→ * Given a card index, returns the 'ord' of the card
471→ */
472→private fun Note.cardIndexToOrd(index: Int): Int {
473→    // We can't use note.numberOfCards() as this uses the database value
474→    return when {
475→        this.notetype.isCloze -> col.clozeNumbersInNote(this)[index] - 1
476→        else -> index
477→    }
478→}
